// Deep Link Handler singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();

  factory DeepLinkHandler() => _instance;

  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;

  /// Initialize deep link handling (initial + stream)
  Future<void> initialize() async {
    // Handle the initial deep link (app was closed)
    await _handleInitialLink();

    // Handle incoming deep links while app is running
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        if (uri != null) {
          _processDeepLink(uri);
        }
      },
      onError: (err) {
        debugPrint('Deep link stream error: $err');
      },
    );
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        _processDeepLink(initialUri);
      }
    } catch (e) {
      debugPrint('Failed to get initial deep link: $e');
    }
  }

  void _processDeepLink(Uri uri) {
    debugPrint('Processing deep link: $uri');

    final DeepLinkRoute? route = DeepLinkParser.parse(uri);

    if (route != null) {
      _navigateToRoute(route);
    } else {
      debugPrint('Unknown deep link route: $uri');
    }
  }

  void _navigateToRoute(DeepLinkRoute route) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not available yet');
      return;
    }

    switch (route.routeName) {
      case '/profile':
        navigator.pushNamed(
          '/profile',
          arguments: route.parameters,
        );
        break;
      case '/payment/confirm':
        navigator.pushNamed(
          '/payment/confirm',
          arguments: route.parameters,
        );
        break;
      case '/campaign':
        navigator.pushNamed(
          '/campaign',
          arguments: route.parameters,
        );
        break;
      case '/notification':
        navigator.pushNamed(
          '/notification',
          arguments: route.parameters,
        );
        break;
      default:
        debugPrint('No navigation handler for route: ${route.routeName}');
    }
  }

  void dispose() {
    _linkSubscription?.cancel();
  }
}

// Deep Link Route model
class DeepLinkRoute {
  final String routeName;
  final Map<String, String> parameters;

  DeepLinkRoute({
    required this.routeName,
    this.parameters = const {},
  });

  @override
  String toString() =>
      'DeepLinkRoute(routeName: $routeName, parameters: $parameters)';
}

// Deep Link Parser
class DeepLinkParser {
  static const String scheme = 'myapp';

  static DeepLinkRoute? parse(Uri uri) {
    // Validate scheme
    if (uri.scheme != scheme && uri.scheme != 'https') {
      debugPrint('Invalid scheme: ${uri.scheme}');
      return null;
    }

    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    // myapp://profile/123 or myapp://profile?id=123
    if (uri.host == 'profile' || (pathSegments.isNotEmpty && pathSegments[0] == 'profile')) {
      String? userId;

      if (uri.host == 'profile' && pathSegments.isNotEmpty) {
        userId = pathSegments[0];
      } else if (pathSegments.length > 1) {
        userId = pathSegments[1];
      }

      userId ??= queryParams['id'];

      final params = <String, String>{};
      if (userId != null) params['userId'] = userId;
      params.addAll(queryParams);

      return DeepLinkRoute(
        routeName: '/profile',
        parameters: params,
      );
    }

    // myapp://payment/confirm?transactionId=abc&amount=99.99
    if (uri.host == 'payment' ||
        (pathSegments.isNotEmpty && pathSegments[0] == 'payment')) {
      final subPath = uri.host == 'payment'
          ? (pathSegments.isNotEmpty ? pathSegments[0] : '')
          : (pathSegments.length > 1 ? pathSegments[1] : '');

      if (subPath == 'confirm') {
        final params = <String, String>{};
        params.addAll(queryParams);

        return DeepLinkRoute(
          routeName: '/payment/confirm',
          parameters: params,
        );
      }
    }

    // myapp://campaign?source=email&campaign_id=summer2024&utm_medium=newsletter
    if (uri.host == 'campaign' ||
        (pathSegments.isNotEmpty && pathSegments[0] == 'campaign')) {
      final params = <String, String>{};
      params.addAll(queryParams);

      if (uri.host == 'campaign' && pathSegments.isNotEmpty) {
        params['campaignSlug'] = pathSegments[0];
      }

      return DeepLinkRoute(
        routeName: '/campaign',
        parameters: params,
      );
    }

    // myapp://notification?type=promo&id=456
    if (uri.host == 'notification' ||
        (pathSegments.isNotEmpty && pathSegments[0] == 'notification')) {
      final params = <String, String>{};
      params.addAll(queryParams);

      return DeepLinkRoute(
        routeName: '/notification',
        parameters: params,
      );
    }

    return null;
  }
}

// App Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case '/':
        return MaterialPageRoute(builder: (_) => const HomeScreen());
      case '/profile':
        final params = settings.arguments as Map<String, String>? ?? {};
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(
            userId: params['userId'] ?? 'unknown',
            source: params['source'],
          ),
        );
      case '/payment/confirm':
        final params = settings.arguments as Map<String, String>? ?? {};
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            transactionId: params['transactionId'] ?? '',
            amount: params['amount'] ?? '0.00',
            status: params['status'],
          ),
        );
      case '/campaign':
        final params = settings.arguments as Map<String, String>? ?? {};
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(parameters: params),
        );
      case '/notification':
        final params = settings.arguments as Map<String, String>? ?? {};
        return MaterialPageRoute(
          builder: (_) => NotificationScreen(parameters: params),
        );
      default:
        return MaterialPageRoute(
          builder: (_) => Scaffold(
            appBar: AppBar(title: const Text('Not Found')),
            body: Center(
              child: Text('Route not found: ${settings.name}'),
            ),
          ),
        );
    }
  }
}

// Wrapper widget to initialize deep links
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();

  @override
  void initState() {
    super.initState();
    // Initialize after the first frame to ensure navigator is ready
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _deepLinkHandler.initialize();
    });
  }

  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return const HomeScreen();
  }
}

